import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Журнал версий: обновления функций | OpenSkills","description":"Просмотрите историю изменений версий OpenSkills, узнайте о командах update, символических ссылках, частных репозиториях и других новых функциях, а также о важных улучшениях и исправлениях.","frontmatter":{"title":"Журнал версий: обновления функций | OpenSkills","sidebarTitle":"Что нового","subtitle":"Журнал версий: обновления функций | OpenSkills","description":"Просмотрите историю изменений версий OpenSkills, узнайте о командах update, символических ссылках, частных репозиториях и других новых функциях, а также о важных улучшениях и исправлениях.","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"ru/numman-ali/openskills/changelog/changelog/index.md","filePath":"ru/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"ru/numman-ali/openskills/changelog/changelog/index.md"};function t(n,l,s,d,h,c){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="журнал-обновлении" tabindex="-1">Журнал обновлений <a class="header-anchor" href="#журнал-обновлении" aria-label="Permalink to &quot;Журнал обновлений&quot;">​</a></h1><p>На этой странице записана история изменений версий OpenSkills, помогающая вам узнать о новых возможностях, улучшениях и исправлениях каждой версии.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="новые-возможности" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Обновление установленных навыков из записанных источников (по умолчанию: обновление всех)</li><li><strong>Отслеживание метаданных источника</strong> - При установке теперь записывается информация об источнике для надежного обновления навыков</li></ul><h3 id="улучшения" tabindex="-1">Улучшения <a class="header-anchor" href="#улучшения" aria-label="Permalink to &quot;Улучшения&quot;">​</a></h3><ul><li><strong>Чтение нескольких навыков</strong> - Команда <code>openskills read</code> теперь поддерживает список имен навыков, разделенных запятыми</li><li><strong>Генерация инструкций по использованию</strong> - Оптимизированы подсказки для вызова команды read в среде shell</li><li><strong>README</strong> - Добавлены инструкции по обновлению и советы по ручному использованию</li></ul><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li><strong>Оптимизация процесса обновления</strong> - Пропуск навыков без метаданных источника с выводом списка таких навыков с предложением переустановить</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="улучшения-1" tabindex="-1">Улучшения <a class="header-anchor" href="#улучшения-1" aria-label="Permalink to &quot;Улучшения&quot;">​</a></h3><ul><li><strong>README</strong> - Уточнены способы установки по умолчанию для локального проекта, удалены избыточные подсказки sync</li><li><strong>Сообщения об установке</strong> - Инсталлятор теперь четко различает установку по умолчанию для локального проекта и опцию <code>--global</code></li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="улучшения-2" tabindex="-1">Улучшения <a class="header-anchor" href="#улучшения-2" aria-label="Permalink to &quot;Улучшения&quot;">​</a></h3><ul><li><strong>Документация и руководства AGENTS.md</strong> - Все примеры команд и генерируемые инструкции по использованию теперь единообразно используют <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="исправления-1" tabindex="-1">Исправления <a class="header-anchor" href="#исправления-1" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li><strong>Установка в Windows</strong> - Исправлена проблема проверки пути в системах Windows (&quot;Security error: Installation path outside target directory&quot;)</li><li><strong>Версия CLI</strong> - <code>npx openskills --version</code> теперь правильно считывает номер версии из package.json</li><li><strong>SKILL.md в корневом каталоге</strong> - Исправлена установка репозиториев с одним навыком, где SKILL.md находится в корне репозитория</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="новые-возможности-1" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности-1" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><ul><li><p><strong>Поддержка символических ссылок</strong> - Навыки теперь можно устанавливать в директорию навыков через символические ссылки (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>Поддержка обновлений навыков на основе git через создание символических ссылок из клонированного репозитория</li><li>Поддержка рабочих процессов локальной разработки навыков</li><li>Поврежденные символические ссылки корректно пропускаются</li></ul></li><li><p><strong>Настраиваемый путь вывода</strong> - Команда sync получила новую опцию <code>--output</code> / <code>-o</code> (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>Можно синхронизировать в любой файл <code>.md</code> (например, <code>.ruler/AGENTS.md</code>)</li><li>Если файл не существует, автоматически создается файл и добавляется заголовок</li><li>При необходимости автоматически создаются вложенные директории</li></ul></li><li><p><strong>Установка по локальному пути</strong> - Поддержка установки навыков из локальных директорий (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>Поддержка абсолютных путей (<code>/path/to/skill</code>)</li><li>Поддержка относительных путей (<code>./skill</code>, <code>../skill</code>)</li><li>Поддержка раскрытия тильды (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>Поддержка частных git репозиториев</strong> - Поддержка установки навыков из частных репозиториев (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URLs (<code>git@github.com:org/private-skills.git</code>)</li><li>HTTPS URLs с аутентификацией</li><li>Автоматическое использование системных SSH ключей</li></ul></li><li><p><strong>Полный набор тестов</strong> - 88 тестов в 6 тестовых файлах</p><ul><li>Модульные тесты для обнаружения символических ссылок, парсинга YAML</li><li>Интеграционные тесты для команд install, sync</li><li>Энд-энд тесты для полного рабочего процесса CLI</li></ul></li></ul><h3 id="улучшения-3" tabindex="-1">Улучшения <a class="header-anchor" href="#улучшения-3" aria-label="Permalink to &quot;Улучшения&quot;">​</a></h3><ul><li><p><strong>Флаг <code>--yes</code> теперь пропускает все подсказки</strong> - Полностью неинтерактивный режим, подходит для CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>Без подсказок при перезаписи существующих навыков</li><li>Отображение сообщения <code>Overwriting: &lt;skill-name&gt;</code> при пропуске подсказок</li><li>Все команды теперь можно запускать в headless-средах</li></ul></li><li><p><strong>Перестановка CI workflow</strong> - Этап сборки теперь запускается перед тестами</p><ul><li>Обеспечивает существование <code>dist/cli.js</code> для энд-энд тестов</li></ul></li></ul><h3 id="безопасность" tabindex="-1">Безопасность <a class="header-anchor" href="#безопасность" aria-label="Permalink to &quot;Безопасность&quot;">​</a></h3><ul><li><strong>Защита от обхода пути</strong> - Проверка, что путь установки остается в пределах целевой директории</li><li><strong>Разыменование символических ссылок</strong> - <code>cpSync</code> использует <code>dereference: true</code> для безопасного копирования целевого объекта символической ссылки</li><li><strong>Нежадные регулярные выражения YAML</strong> - Защита от потенциальной атаки ReDoS при парсинге frontmatter</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="исправления-2" tabindex="-1">Исправления <a class="header-anchor" href="#исправления-2" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Очистка документации README - удалены дублирующиеся разделы и неверные флаги</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="новые-возможности-2" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности-2" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><ul><li>Флаг <code>--universal</code> для установки навыков в <code>.agent/skills/</code> вместо <code>.claude/skills/</code><ul><li>Подходит для многоагентных сред (Claude Code + Cursor/Windsurf/Aider)</li><li>Избегает конфликтов с плагинами нативного маркетплейса Claude Code</li></ul></li></ul><h3 id="улучшения-4" tabindex="-1">Улучшения <a class="header-anchor" href="#улучшения-4" aria-label="Permalink to &quot;Улучшения&quot;">​</a></h3><ul><li>Локальная установка в проект теперь является опцией по умолчанию (ранее глобальная установка)</li><li>Навыки по умолчанию устанавливаются в <code>./.claude/skills/</code></li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="новые-возможности-3" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности-3" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><ul><li>Полная одностраничная документация README с глубоким техническим анализом</li><li>Параллельное сравнение с Claude Code</li></ul><h3 id="исправления-3" tabindex="-1">Исправления <a class="header-anchor" href="#исправления-3" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Метки расположения теперь корректно отображают <code>project</code> или <code>global</code> в зависимости от места установки</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="новые-возможности-4" tabindex="-1">Новые возможности <a class="header-anchor" href="#новые-возможности-4" aria-label="Permalink to &quot;Новые возможности&quot;">​</a></h3><ul><li>Первоначальный выпуск</li><li><code>npx openskills install &lt;source&gt;</code> - Установка навыков из репозиториев GitHub</li><li><code>npx openskills sync</code> - Генерация XML <code>&lt;available_skills&gt;</code> для AGENTS.md</li><li><code>npx openskills list</code> - Отображение установленных навыков</li><li><code>npx openskills read &lt;name&gt;</code> - Загрузка содержимого навыка для агента</li><li><code>npx openskills manage</code> - Интерактивное удаление навыков</li><li><code>npx openskills remove &lt;name&gt;</code> - Удаление указанного навыка</li><li>Интерфейс TUI для всех команд</li><li>Поддержка формата SKILL.md от Anthropic</li><li>Прогрессивное раскрытие (загрузка навыков по требованию)</li><li>Поддержка упакованных ресурсов (references/, scripts/, assets/)</li></ul><hr><h2 id="приложение-ссылки-на-исходныи-код" tabindex="-1">Приложение: Ссылки на исходный код <a class="header-anchor" href="#приложение-ссылки-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылки на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th></tr></thead><tbody><tr><td>Оригинал журнала изменений</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=e(r,[["render",t]]);export{g as __pageData,m as default};
